import React from "react";

function GoogleMapView({ origin, destination }) {

  if (!origin || !destination) {

    return (
      <p style={{ textAlign: "center" }}>
        Enter destination to start navigation
      </p>
    );

  }

  const mapURL =
    `https://www.google.com/maps?q=${origin}+to+${destination}&output=embed`;

  return (

    <div style={{ marginTop: "30px" }}>

      <iframe
        title="google-map"
        width="100%"
        height="450"
        style={{ border: "0", borderRadius: "10px" }}
        loading="lazy"
        allowFullScreen
        src={mapURL}
      />

    </div>

  );

}

export default GoogleMapView;
